    capitalRecovery({capitalCost,discountRate,lifetimeYears}){const P=positive(capitalCost,'Capital cost'),r=n(discountRate),N=positive(lifetimeYears,'Lifetime');const crf=Math.abs(r)<1e-12?1/N:r*Math.pow(1+r,N)/(Math.pow(1+r,N)-1);return{capitalRecoveryFactor:round(crf),annualizedCapitalCost:round(P*crf)};},
    lcoe({capitalCost,annualFixedCost,variableCostPerMWh,annualEnergyMWh,discountRate,lifetimeYears}){const P=positive(capitalCost,'Capital cost'),fixed=nonnegative(annualFixedCost,'Annual fixed cost'),v=nonnegative(variableCostPerMWh,'Variable cost'),E=positive(annualEnergyMWh,'Annual energy'),r=n(discountRate),N=Math.floor(positive(lifetimeYears,'Lifetime'));let cost=P,energy=0;for(let y=1;y<=N;y++){const d=Math.pow(1+r,y);cost+=(fixed+v*E)/d;energy+=E/d;}return{lcoePerMWh:round(cost/energy),presentCost:round(cost),presentEnergyMWh:round(energy)};},
    lcos({capitalCost,annualFixedCost,chargingEnergyMWh,dischargedEnergyMWh,chargingEnergyCostPerMWh,discountRate,lifetimeYears}){const P=positive(capitalCost,'Capital cost'),fixed=nonnegative(annualFixedCost,'Annual fixed cost'),charge=nonnegative(chargingEnergyMWh,'Charging energy'),out=positive(dischargedEnergyMWh,'Discharged energy'),price=nonnegative(chargingEnergyCostPerMWh,'Charging cost'),r=n(discountRate),N=Math.floor(positive(lifetimeYears,'Lifetime'));let cost=P,energy=0;for(let y=1;y<=N;y++){const d=Math.pow(1+r,y);cost+=(fixed+charge*price)/d;energy+=out/d;}return{lcosPerMWh:round(cost/energy),presentCost:round(cost),presentDischargedEnergyMWh:round(energy)};},
