    priceSensitivity({basePrice,lowMultiplier,highMultiplier,steps,quantity}){const N=Math.max(2,Math.floor(positive(steps,'Steps'))),lo=n(lowMultiplier),hi=n(highMultiplier),p=positive(basePrice,'Base price'),q=nonnegative(quantity,'Quantity');const series=Array.from({length:N},(_,i)=>{const m=lo+(hi-lo)*i/(N-1);return{x:m,totalCost:p*m*q};});return{minimumCost:round(series[0].totalCost),maximumCost:round(series.at(-1).totalCost),series};},

    seriesReliability({componentReliabilities}){const xs=list(componentReliabilities);if(!xs.length)throw new Error('Provide component reliabilities.');xs.forEach((x,i)=>frac(x,`Component reliability ${i+1}`));return{systemReliability:round(xs.reduce((p,x)=>p*x,1)),componentCount:xs.length};},
